resource "aws_iam_role" "synthetic_role_122" {
  name = "synthetic_role_122"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_122_policy" {
  name   = "synthetic_role_122-policy"
  role   = aws_iam_role.synthetic_role_122.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "lambda:CreateFunction",
                "lambda:UpdateFunctionCode",
                "lambda:CreateFunction"
            ],
            "Resource": "arn:aws:ec2:*:*:*"
        }
    ]
})
}
